module RefModule (
    input [3:0] in0,
    input [3:0] in1,
    input SUB,
    output reg [3:0] out
);
  wire [3:0] _tap_in0 = in0 & {4{1'b1}};


    always @(*) begin
        if (SUB) begin
            out <= in0 - in1;
        end else begin
            out <= in0 + in1;
        end
    end

endmodule
